function coerce(value) {
  if (value == null) return null;
  if (typeof value === "object") return value;
  if (typeof value === "string") {
    let s = value.replace(/```json/gi, "").replace(/```/g, "").trim();
    const first = s.indexOf("{");
    const last = s.lastIndexOf("}");
    if (first !== -1 && last !== -1 && last > first) {
      s = s.slice(first, last + 1);
    }
    try { return JSON.parse(s); } catch { return null; }
  }
  return null;
}

let data = $json.output ?? $json;
let parsed = coerce(data);

if (!parsed) {
  throw new Error("Research agent returned unparseable output.\n\nRaw output:\n" + JSON.stringify(data).slice(0, 1500));
}

if (parsed.output && typeof parsed.output === "object") {
  parsed = parsed.output;
}

const categoryMap = {
  trending_ai_news: (item) => ({
    headline: item.headline || "",
    summary: item.summary || item.why_it_matters || "",
    source: item.source || "",
    date: item.date || "",
    url: item.url || "",
    category: "trending_ai_news"
  }),
  ai_agents_updates: (item) => ({
    headline: item.headline || "",
    summary: item.summary || item.key_takeaway || "",
    source: item.source || "",
    date: item.date || "",
    url: item.url || "",
    category: "ai_agents_updates"
  }),
  ai_coding_news: (item) => ({
    headline: item.headline || "",
    summary: item.summary || item.developer_impact || "",
    source: item.source || "",
    date: item.date || "",
    url: item.url || "",
    category: "ai_coding_news"
  })
};

const allItems = [];
for (const [key, mapper] of Object.entries(categoryMap)) {
  const arr = parsed[key];
  if (Array.isArray(arr)) {
    arr.forEach(item => {
      if (item && (item.headline || item.summary)) {
        allItems.push({ json: mapper(item) });
      }
    });
  }
}

if (allItems.length === 0) {
  throw new Error("Research agent returned no news items. Parsed payload:\n" + JSON.stringify(parsed).slice(0, 1500));
}

return allItems;

const allInputs = $input.all();
let allNewsItems = [];

for (const input of allInputs) {
  let raw = input.json.output ?? input.json;

  if (typeof raw === "string") {
    raw = raw.replace(/```json/gi, "").replace(/```/g, "").trim();
    try {
      raw = JSON.parse(raw);
    } catch (err) {
      continue;
    }
  }

  if (Array.isArray(raw?.news)) {
    raw.news.forEach(item => {
      allNewsItems.push({
        headline: item.headline || "",
        summary: item.facts || item.summary || "",
        caption: item.caption || ""
      });
    });
  }
}

if (allNewsItems.length === 0) {
  throw new Error("No news items found.");
}

const selected = allNewsItems[Math.floor(Math.random() * allNewsItems.length)];
return [{ json: selected }];

function extractJson(value) {
  if (value && typeof value === "object") return value;
  if (typeof value !== "string") return null;
  const first = value.indexOf("{");
  const last = value.lastIndexOf("}");
  if (first === -1 || last === -1 || last <= first) return null;
  try { return JSON.parse(value.slice(first, last + 1)); } catch (e) { return null; }
}

// The Agent + Structured Output Parser delivers a parsed object on $json.output.
// Fall back to raw text / content only if that is ever missing.
let payload = $json.output ?? $json;
let parsed = (payload && typeof payload === "object") ? payload : extractJson(payload);
if (!parsed) {
  parsed = extractJson($json.text) || extractJson($json.content) || extractJson($json.output);
}

let slides = null;
if (parsed) {
  if (Array.isArray(parsed.slides)) slides = parsed.slides;
  else if (parsed.output && Array.isArray(parsed.output.slides)) slides = parsed.output.slides;
}

if (!slides || slides.length === 0) {
  throw new Error("Missing slides array. Parsed payload:\n" + JSON.stringify(parsed ?? payload).slice(0, 1500));
}

return slides.map((slide, i) => ({
  json: {
    slide_number: typeof slide.slide_number === "number" ? slide.slide_number : i + 1,
    text: typeof slide.text === "string" ? slide.text : String(slide.text ?? "")
  }
}));

